     1â†’#!/usr/bin/env bun
     2â†’/**
     3â†’ * LoadContext.hook.ts - Inject PAI context into Claude's Context (SessionStart)
     4â†’ *
     5â†’ * PURPOSE:
     6â†’ * The foundational context injection hook. Reads the PAI SKILL.md plus
     7â†’ * AI Steering Rules (SYSTEM and USER) and outputs them as a <system-reminder>
     8â†’ * to stdout.
     9â†’ *
    10â†’ * TRIGGER: SessionStart
    11â†’ *
    12â†’ * INPUT:
    13â†’ * - Environment: PAI_DIR, TIME_ZONE
    14â†’ * - Files: skills/PAI/SKILL.md, skills/PAI/SYSTEM/AISTEERINGRULES.md,
    15â†’ *          skills/PAI/USER/AISTEERINGRULES.md, MEMORY/STATE/progress/*.json
    16â†’ *
    17â†’ * OUTPUT:
    18â†’ * - stdout: <system-reminder> containing SKILL.md + AI Steering Rules
    19â†’ * - stdout: Active work summary if previous sessions have pending work
    20â†’ * - stderr: Status messages and errors
    21â†’ * - exit(0): Normal completion
    22â†’ * - exit(1): Critical failure (SKILL.md not found)
    23â†’ *
    24â†’ * DESIGN PHILOSOPHY:
    25â†’ * Load SKILL.md and AI Steering Rules at session start. These are critical for
    26â†’ * consistent behavior. Other context (USER docs, SYSTEM docs) loads dynamically
    27â†’ * based on the Context Loading section in SKILL.md.
    28â†’ *
    29â†’ * ERROR HANDLING:
    30â†’ * - Missing SKILL.md: Fatal error, exits with code 1
    31â†’ * - Missing steering rules: Logged warning, continues (non-fatal)
    32â†’ * - Progress file errors: Logged, continues (non-fatal)
    33â†’ * - Date command failure: Falls back to ISO timestamp
    34â†’ *
    35â†’ * PERFORMANCE:
    36â†’ * - Blocking: Yes (context is essential)
    37â†’ * - Typical execution: <50ms
    38â†’ * - Skipped for subagents: Yes (they get context differently)
    39â†’ */
    40â†’
    41â†’import { readFileSync, existsSync, readdirSync, writeFileSync } from 'fs';
    42â†’import { join } from 'path';
    43â†’import { execSync } from 'child_process';
    44â†’import { getPaiDir } from './lib/paths';
    45â†’import { recordSessionStart } from './lib/notifications';
    46â†’
    47â†’/**
    48â†’ * Reset tab title to clean state at session start.
    49â†’ * Prevents stale tab titles from previous sessions bleeding through.
    50â†’ * Cross-platform support for Windows Terminal, Kitty, and others.
    51â†’ */
    52â†’function resetTabTitle(paiDir: string): void {
    53â†’  const cleanTitle = 'New Session';
    54â†’  const stateFile = join(paiDir, 'MEMORY', 'STATE', 'tab-title.json');
    55â†’
    56â†’  try {
    57â†’    const isWindows = process.platform === 'win32';
    58â†’    const isKitty = process.env.TERM === 'xterm-kitty' || process.env.KITTY_LISTEN_ON;
    59â†’
    60â†’    if (isWindows) {
    61â†’      // Windows Terminal escape sequence
    62â†’      try {
    63â†’        const osc = `\x1b]0;${cleanTitle}\x07`;
    64â†’        process.stdout.write(osc);
    65â†’        console.error('đź”„ Tab title reset (Windows Terminal)');
    66â†’      } catch (writeError) {
    67â†’        // Non-critical - tab title is cosmetic
    68â†’        console.error('đź”„ Tab title reset skipped (stdout unavailable on Windows)');
    69â†’      }
    70â†’    } else if (isKitty) {
    71â†’      // Reset Kitty tab title immediately
    72â†’      execSync(`kitty @ set-tab-title "${cleanTitle}"`, { stdio: 'ignore', timeout: 2000 });
    73â†’      // Reset tab color to default (dark blue for active, no special color for inactive)
    74â†’      execSync(
    75â†’        `kitten @ set-tab-color --self active_bg=#002B80 active_fg=#FFFFFF inactive_bg=none inactive_fg=#A0A0A0`,
    76â†’        { stdio: 'ignore', timeout: 2000 }
    77â†’      );
    78â†’      console.error('đź”„ Tab title reset (Kitty)');
    79â†’    } else {
    80â†’      // Fallback escape codes for other terminals
    81â†’      try {
    82â†’        const osc = `\x1b]0;${cleanTitle}\x07`;
    83â†’        process.stdout.write(osc);
    84â†’        console.error('đź”„ Tab title reset (fallback)');
    85â†’      } catch (writeError) {
    86â†’        // Silent failure - non-critical
    87â†’        if (process.env.DEBUG_HOOKS === 'true') {
    88â†’          console.error('đź”„ Tab title reset skipped:', writeError);
    89â†’        }
    90â†’      }
    91â†’    }
    92â†’
    93â†’    // Reset state file to prevent any stale data
    94â†’    const cleanState = {
    95â†’      title: cleanTitle,
    96â†’      rawTitle: cleanTitle,
    97â†’      timestamp: new Date().toISOString(),
    98â†’      state: 'idle'
    99â†’    };
   100â†’    writeFileSync(stateFile, JSON.stringify(cleanState, null, 2));
   101â†’    console.error('đź”„ Tab state file reset');
   102â†’  } catch (err) {
   103â†’    console.error(`âš ď¸Ź Failed to reset tab title: ${err}`);
   104â†’    // Non-fatal, continue with session
   105â†’  }
   106â†’}
