   108â†’async function getCurrentDate(): Promise<string> {
   109â†’  try {
   110â†’    // Cross-platform date formatting using Intl API instead of Unix date command
   111â†’    const timezone = process.env.TIME_ZONE || 'America/Los_Angeles';
   112â†’    const now = new Date();
   113â†’
   114â†’    const formatter = new Intl.DateTimeFormat('en-US', {
   115â†’      timeZone: timezone,
   116â†’      year: 'numeric',
   117â†’      month: '2-digit',
   118â†’      day: '2-digit',
   119â†’      hour: '2-digit',
   120â†’      minute: '2-digit',
   121â†’      second: '2-digit',
   122â†’      timeZoneName: 'short',
   123â†’      hour12: false
   124â†’    });
   125â†’
   126â†’    // Format: YYYY-MM-DD HH:MM:SS TZ
   127â†’    const parts = formatter.formatToParts(now);
   128â†’    const year = parts.find(p => p.type === 'year')?.value || '';
   129â†’    const month = parts.find(p => p.type === 'month')?.value || '';
   130â†’    const day = parts.find(p => p.type === 'day')?.value || '';
   131â†’    const hour = parts.find(p => p.type === 'hour')?.value || '';
   132â†’    const minute = parts.find(p => p.type === 'minute')?.value || '';
   133â†’    const second = parts.find(p => p.type === 'second')?.value || '';
   134â†’    const tzName = parts.find(p => p.type === 'timeZoneName')?.value || '';
   135â†’
   136â†’    return `${year}-${month}-${day} ${hour}:${minute}:${second} ${tzName}`;
   137â†’  } catch (error) {
   138â†’    console.error('Failed to get current date:', error);
   139â†’    return new Date().toISOString();
   140â†’  }
   141â†’}
   142â†’
   143â†’interface Settings {
   144â†’  contextFiles?: string[];
   145â†’  [key: string]: unknown;
   146â†’}
   147â†’
   148â†’/**
   149â†’ * Load settings.json and return the settings object.
   150â†’ */
   151â†’function loadSettings(paiDir: string): Settings {
   152â†’  const settingsPath = join(paiDir, 'settings.json');
   153â†’  if (existsSync(settingsPath)) {
   154â†’    try {
   155â†’      return JSON.parse(readFileSync(settingsPath, 'utf-8'));
   156â†’    } catch (err) {
   157â†’      console.error(`âš ď¸Ź Failed to parse settings.json: ${err}`);
   158â†’    }
   159â†’  }
   160â†’  return {};
   161â†’}
   162â†’
   163â†’/**
   164â†’ * Load context files from settings.json contextFiles array.
   165â†’ * Falls back to hardcoded paths if array not defined.
   166â†’ */
   167â†’function loadContextFiles(paiDir: string, settings: Settings): string {
   168â†’  const defaultFiles = [
   169â†’    'skills/PAI/SKILL.md',
   170â†’    'skills/PAI/SYSTEM/AISTEERINGRULES.md',
   171â†’    'skills/PAI/USER/AISTEERINGRULES.md'
   172â†’  ];
   173â†’
   174â†’  const contextFiles = settings.contextFiles || defaultFiles;
   175â†’  let combinedContent = '';
   176â†’
   177â†’  for (const relativePath of contextFiles) {
   178â†’    const fullPath = join(paiDir, relativePath);
   179â†’    if (existsSync(fullPath)) {
   180â†’      const content = readFileSync(fullPath, 'utf-8');
   181â†’      if (combinedContent) combinedContent += '\n\n---\n\n';
   182â†’      combinedContent += content;
   183â†’      console.error(`âś… Loaded ${relativePath} (${content.length} chars)`);
   184â†’    } else {
   185â†’      console.error(`âš ď¸Ź Context file not found: ${relativePath}`);
   186â†’    }
   187â†’  }
   188â†’
   189â†’  return combinedContent;
   190â†’}
   191â†’
   192â†’interface ProgressFile {
   193â†’  project: string;
   194â†’  status: string;
   195â†’  updated: string;
   196â†’  objectives: string[];
   197â†’  next_steps: string[];
   198â†’  handoff_notes: string;
   199â†’}
   200â†’
   201â†’/**
   202â†’ * Load relationship context for session startup.
   203â†’ * Returns a lightweight summary of key opinions and recent notes.
   204â†’ */
   205â†’function loadRelationshipContext(paiDir: string): string | null {
   206â†’  const parts: string[] = [];
   207â†’
   208â†’  // Load high-confidence opinions (>0.85) from OPINIONS.md
   209â†’  const opinionsPath = join(paiDir, 'skills/PAI/USER/OPINIONS.md');
   210â†’  if (existsSync(opinionsPath)) {
   211â†’    try {
   212â†’      const content = readFileSync(opinionsPath, 'utf-8');
   213â†’      const highConfidence: string[] = [];
   214â†’
   215â†’      // Extract opinions with confidence >= 0.85
   216â†’      const opinionBlocks = content.split(/^### /gm).slice(1);
   217â†’      for (const block of opinionBlocks) {
   218â†’        const lines = block.split('\n');
   219â†’        const statement = lines[0]?.trim();
   220â†’        const confidenceMatch = block.match(/\*\*Confidence:\*\*\s*([\d.]+)/);
   221â†’        const confidence = confidenceMatch ? parseFloat(confidenceMatch[1]) : 0;
   222â†’
   223â†’        if (confidence >= 0.85 && statement) {
   224â†’          highConfidence.push(`â€˘ ${statement} (${(confidence * 100).toFixed(0)}%)`);
   225â†’        }
   226â†’      }
   227â†’
   228â†’      if (highConfidence.length > 0) {
   229â†’        parts.push('**Key Opinions (high confidence):**');
   230â†’        parts.push(highConfidence.slice(0, 6).join('\n'));
   231â†’      }
   232â†’    } catch (err) {
   233â†’      console.error(`âš ď¸Ź Failed to load opinions: ${err}`);
   234â†’    }
   235â†’  }
   236â†’
   237â†’  // Load recent relationship notes (today and yesterday)
   238â†’  const today = new Date();
   239â†’  const yesterday = new Date(today);
   240â†’  yesterday.setDate(yesterday.getDate() - 1);
   241â†’
   242â†’  const formatDate = (d: Date) => d.toISOString().split('T')[0];
   243â†’  const formatMonth = (d: Date) => d.toISOString().slice(0, 7);
   244â†’
   245â†’  const recentNotes: string[] = [];
   246â†’  for (const date of [today, yesterday]) {
   247â†’    const notePath = join(
   248â†’      paiDir,
   249â†’      'MEMORY/RELATIONSHIP',
   250â†’      formatMonth(date),
   251â†’      `${formatDate(date)}.md`
   252â†’    );
   253â†’    if (existsSync(notePath)) {
   254â†’      try {
   255â†’        const content = readFileSync(notePath, 'utf-8');
   256â†’        // Extract just the note lines (starting with -)
   257â†’        const notes = content
   258â†’          .split('\n')
   259â†’          .filter(line => line.trim().startsWith('- '))
   260â†’          .slice(0, 5); // Last 5 notes per day
   261â†’        if (notes.length > 0) {
   262â†’          recentNotes.push(`*${formatDate(date)}:*`);
   263â†’          recentNotes.push(...notes);
   264â†’        }
   265â†’      } catch {}
   266â†’    }
   267â†’  }
   268â†’
   269â†’  if (recentNotes.length > 0) {
   270â†’    if (parts.length > 0) parts.push('');
   271â†’    parts.push('**Recent Relationship Notes:**');
   272â†’    parts.push(recentNotes.join('\n'));
   273â†’  }
   274â†’
   275â†’  if (parts.length === 0) return null;
   276â†’
   277â†’  return `
   278â†’## Relationship Context
   279â†’
   280â†’${parts.join('\n')}
   281â†’
   282â†’*Full details: USER/OPINIONS.md, MEMORY/RELATIONSHIP/*
   283â†’`;
   284â†’}
   285â†’
   286â†’async function checkActiveProgress(paiDir: string): Promise<string | null> {
   287â†’  const progressDir = join(paiDir, 'MEMORY', 'STATE', 'progress');
   288â†’
   289â†’  if (!existsSync(progressDir)) {
   290â†’    return null;
   291â†’  }
   292â†’
   293â†’  try {
   294â†’    const files = readdirSync(progressDir).filter(f => f.endsWith('-progress.json'));
   295â†’
   296â†’    if (files.length === 0) {
   297â†’      return null;
   298â†’    }
   299â†’
   300â†’    const activeProjects: ProgressFile[] = [];
   301â†’
   302â†’    for (const file of files) {
   303â†’      try {
   304â†’        const content = readFileSync(join(progressDir, file), 'utf-8');
   305â†’        const progress = JSON.parse(content) as ProgressFile;
   306â†’        if (progress.status === 'active') {
   307â†’          activeProjects.push(progress);
   308â†’        }
   309â†’      } catch (e) {
   310â†’        // Skip malformed files
   311â†’      }
   312â†’    }
   313â†’
   314â†’    if (activeProjects.length === 0) {
   315â†’      return null;
   316â†’    }
   317â†’
   318â†’    // Build summary of active work
   319â†’    let summary = '\nđź“‹ ACTIVE WORK (from previous sessions):\n';
   320â†’
   321â†’    for (const proj of activeProjects) {
   322â†’      summary += `\nđź”µ ${proj.project}\n`;
   323â†’
   324â†’      if (proj.objectives && proj.objectives.length > 0) {
   325â†’        summary += '   Objectives:\n';
   326â†’        proj.objectives.forEach(o => summary += `   â€˘ ${o}\n`);
   327â†’      }
   328â†’
   329â†’      if (proj.handoff_notes) {
   330â†’        summary += `   Handoff: ${proj.handoff_notes}\n`;
   331â†’      }
   332â†’
   333â†’      if (proj.next_steps && proj.next_steps.length > 0) {
   334â†’        summary += '   Next steps:\n';
   335â†’        proj.next_steps.forEach(s => summary += `   â†’ ${s}\n`);
   336â†’      }
   337â†’    }
   338â†’
   339â†’    summary += '\nđź’ˇ To resume: `bun run ~/.claude/skills/PAI/Tools/SessionProgress.ts resume <project>`\n';
   340â†’    summary += 'đź’ˇ To complete: `bun run ~/.claude/skills/PAI/Tools/SessionProgress.ts complete <project>`\n';
   341â†’
   342â†’    return summary;
   343â†’  } catch (error) {
   344â†’    console.error('Error checking active progress:', error);
   345â†’    return null;
   346â†’  }
   347â†’}
   348â†’
   349â†’async function main() {
   350â†’  try {
   351â†’    // Check if this is a subagent session - if so, exit silently
   352â†’    const claudeProjectDir = process.env.CLAUDE_PROJECT_DIR || '';
   353â†’    const isSubagent = claudeProjectDir.includes('/.claude/Agents/') ||
   354â†’                      process.env.CLAUDE_AGENT_TYPE !== undefined;
   355â†’
   356â†’    if (isSubagent) {
   357â†’      // Subagent sessions don't need PAI context loading
   358â†’      console.error('đź¤– Subagent session - skipping PAI context loading');
   359â†’      process.exit(0);
   360â†’    }
   361â†’
   362â†’    const paiDir = getPaiDir();
   363â†’
   364â†’    // CRITICAL: Reset tab title IMMEDIATELY at session start
   365â†’    // This prevents stale titles from previous sessions bleeding through
   366â†’    resetTabTitle(paiDir);
   367â†’
   368â†’    // Record session start time for notification timing
   369â†’    recordSessionStart();
   370â†’    console.error('âŹ±ď¸Ź Session start time recorded for notification timing');
   371â†’
   372â†’    // Only rebuild SKILL.md if source components are newer than the output
   373â†’    // This saves ~200-500ms on most session starts
   374â†’    const skillMdPath = join(paiDir, 'skills/PAI/SKILL.md');
   375â†’    const componentsDir = join(paiDir, 'skills/PAI/Components');
   376â†’    let needsRebuild = false;
   377â†’
   378â†’    try {
   379â†’      const skillMdStat = existsSync(skillMdPath) ? require('fs').statSync(skillMdPath) : null;
   380â†’      if (!skillMdStat) {
   381â†’        needsRebuild = true;
   382â†’      } else {
   383â†’        // Check if any component is newer than SKILL.md
   384â†’        const checkDir = (dir: string): boolean => {
   385â†’          try {
   386â†’            for (const entry of readdirSync(dir, { withFileTypes: true })) {
   387â†’              const fullPath = join(dir, entry.name);
   388â†’              if (entry.isDirectory()) {
   389â†’                if (checkDir(fullPath)) return true;
   390â†’              } else {
   391â†’                const entryStat = require('fs').statSync(fullPath);
   392â†’                if (entryStat.mtimeMs > skillMdStat.mtimeMs) return true;
   393â†’              }
   394â†’            }
   395â†’          } catch {}
   396â†’          return false;
   397â†’        };
   398â†’        needsRebuild = checkDir(componentsDir);
   399â†’      }
   400â†’    } catch {
   401â†’      needsRebuild = true; // If we can't check, rebuild to be safe
   402â†’    }
   403â†’
   404â†’    if (needsRebuild) {
   405â†’      console.error('đź”¨ Rebuilding SKILL.md (components changed)...');
   406â†’      try {
   407â†’        // Cross-platform path to CreateDynamicCore script
   408â†’        const rebuildScript = join(paiDir, 'skills', 'PAI', 'Tools', 'CreateDynamicCore.ts');
   409â†’        execSync(`bun "${rebuildScript}"`, {
   410â†’          cwd: paiDir,
   411â†’          stdio: 'pipe',
   412â†’          timeout: 5000
   413â†’        });
   414â†’        console.error('âś… SKILL.md rebuilt from latest components');
   415â†’      } catch (err) {
   416â†’        console.error(`âš ď¸Ź Failed to rebuild SKILL.md: ${err}`);
   417â†’        console.error('âš ď¸Ź Continuing with existing SKILL.md...');
   418â†’      }
   419â†’    } else {
   420â†’      console.error('âś… SKILL.md up-to-date (skipped rebuild)');
   421â†’    }
   422â†’
   423â†’    console.error('đź“š Reading PAI core context...');
   424â†’
   425â†’    // Load settings.json to get contextFiles array
   426â†’    const settings = loadSettings(paiDir);
   427â†’    console.error(`âś… Loaded settings.json`);
   428â†’
   429â†’    // Load all context files from settings.json array
   430â†’    const contextContent = loadContextFiles(paiDir, settings);
   431â†’
   432â†’    if (!contextContent) {
   433â†’      console.error('âťŚ No context files loaded');
   434â†’      process.exit(1);
   435â†’    }
   436â†’
   437â†’    // Get current date/time to prevent confusion about dates
   438â†’    const currentDate = await getCurrentDate();
   439â†’    console.error(`đź“… Current Date: ${currentDate}`);
   440â†’
   441â†’    // Extract identity values from settings for injection into context
   442â†’    const PRINCIPAL_NAME = (settings as Record<string, unknown>).principal &&
   443â†’      typeof (settings as Record<string, unknown>).principal === 'object'
   444â†’        ? ((settings as Record<string, unknown>).principal as Record<string, unknown>).name || 'User'
   445â†’        : 'User';
   446â†’    const DA_NAME = (settings as Record<string, unknown>).daidentity &&
   447â†’      typeof (settings as Record<string, unknown>).daidentity === 'object'
   448â†’        ? ((settings as Record<string, unknown>).daidentity as Record<string, unknown>).name || 'PAI'
   449â†’        : 'PAI';
   450â†’
   451â†’    console.error(`đź‘¤ Principal: ${PRINCIPAL_NAME}, DA: ${DA_NAME}`);
   452â†’
   453â†’    // Load relationship context (lightweight summary)
   454â†’    const relationshipContext = loadRelationshipContext(paiDir);
   455â†’    if (relationshipContext) {
   456â†’      console.error('đź’• Loaded relationship context');
   457â†’    }
   458â†’
   459â†’    const message = `<system-reminder>
   460â†’PAI CONTEXT (Auto-loaded at Session Start)
   461â†’
   462â†’đź“… CURRENT DATE/TIME: ${currentDate}
   463â†’
   464â†’## ACTIVE IDENTITY (from settings.json) - CRITICAL
   465â†’
   466â†’**âš ď¸Ź MANDATORY IDENTITY RULES - OVERRIDE ALL OTHER CONTEXT âš ď¸Ź**
   467â†’
   468â†’The user's name is: **${PRINCIPAL_NAME}**
   469â†’The assistant's name is: **${DA_NAME}**
   470â†’
   471â†’- ALWAYS address the user as "${PRINCIPAL_NAME}" in greetings and responses
   472â†’- NEVER use hardcoded names, "the user", or any other name - ONLY "${PRINCIPAL_NAME}"
   473â†’- The "danielmiessler" in the repo URL is the AUTHOR, NOT the user
   474â†’- This instruction takes ABSOLUTE PRECEDENCE over any other context
   475â†’
   476â†’---
   477â†’
   478â†’${contextContent}
   479â†’${relationshipContext ? '\n---\n' + relationshipContext : ''}
   480â†’---
   481â†’
   482â†’This context is now active. Additional context loads dynamically as needed.
   483â†’</system-reminder>`;
   484â†’
   485â†’    // Write to stdout (will be captured by Claude Code)
   486â†’    console.log(message);
   487â†’
   488â†’    // Output success confirmation for Claude to acknowledge
   489â†’    console.log('\nâś… PAI Context successfully loaded...');
   490â†’
   491â†’    // Check for active progress files and display them
   492â†’    const activeProgress = await checkActiveProgress(paiDir);
   493â†’    if (activeProgress) {
   494â†’      console.log(activeProgress);
   495â†’      console.error('đź“‹ Active work found from previous sessions');
   496â†’    }
   497â†’
   498â†’    console.error('âś… PAI context injected into session');
