    95â†’function validate(taskPath: string, currentWork: CurrentWork): ValidationResult {
    96â†’  const result: ValidationResult = {
    97â†’    valid: true,
    98â†’    warnings: [],
    99â†’    errors: [],
   100â†’  };
   101â†’
   102â†’  // Check ISC.json
   103â†’  const isc = readISC(taskPath);
   104â†’  if (!isc) {
   105â†’    result.errors.push('ISC.json not found or unreadable');
   106â†’    result.valid = false;
   107â†’    return result;
   108â†’  }
   109â†’
   110â†’  // Rule 1: Criteria array must be non-empty
   111â†’  if (!isc.criteria || isc.criteria.length === 0) {
   112â†’    result.warnings.push('ISC.json criteria array is EMPTY - algorithm may not have executed properly');
   113â†’  }
   114â†’
   115â†’  // Rule 2: Check if ISC.json was modified after session start
   116â†’  const iscPath = join(taskPath, 'ISC.json');
   117â†’  const iscModTime = getFileModTime(iscPath);
   118â†’  const sessionStart = new Date(currentWork.created_at);
   119â†’
   120â†’  if (iscModTime && iscModTime <= sessionStart) {
   121â†’    result.warnings.push('ISC.json not modified since session start - no updates during algorithm execution');
   122â†’  }
   123â†’
   124â†’  // Check THREAD.md
   125â†’  const thread = readThread(taskPath);
   126â†’  if (!thread) {
   127â†’    result.errors.push('THREAD.md not found or unreadable');
   128â†’    result.valid = false;
   129â†’    return result;
   130â†’  }
   131â†’
   132â†’  // Rule 3: Check for _Pending..._ placeholders
   133â†’  const pendingCount = (thread.match(/_Pending\.\.\._/g) || []).length;
   134â†’  if (pendingCount > 0) {
   135â†’    result.warnings.push(`THREAD.md has ${pendingCount} phases still marked _Pending..._ - algorithm phases not logged`);
   136â†’  }
   137â†’
   138â†’  return result;
   139â†’}
