   150â†’  hookInput: { session_id: string }
   151â†’): Promise<ISCValidationResult> {
   152â†’  const result: ISCValidationResult = {
   153â†’    shouldBlock: false,
   154â†’    warnings: [],
   155â†’    errors: [],
   156â†’  };
   157â†’
   158â†’  const currentWork = readCurrentWork();
   159â†’  if (!currentWork) {
   160â†’    console.error('[ISCValidator] No current work found - skipping validation');
   161â†’    return result;
   162â†’  }
   163â†’
   164â†’  // Skip if session IDs don't match
   165â†’  if (currentWork.session_id !== hookInput.session_id) {
   166â†’    console.error('[ISCValidator] Session ID mismatch - skipping validation');
   167â†’    return result;
   168â†’  }
   169â†’
   170â†’  const taskPath = join(WORK_DIR, currentWork.session_dir, 'tasks', currentWork.current_task);
   171â†’  if (!existsSync(taskPath)) {
   172â†’    console.error(`[ISCValidator] Task path not found: ${taskPath}`);
   173â†’    return result;
   174â†’  }
   175â†’
   176â†’  const validationResult = validate(taskPath, currentWork);
   177â†’  result.warnings = validationResult.warnings;
   178â†’  result.errors = validationResult.errors;
   179â†’
   180â†’  // Log results
   181â†’  if (result.errors.length > 0) {
   182â†’    console.error('[ISCValidator] ERRORS:');
   183â†’    result.errors.forEach((e) => console.error(`  âťŚ ${e}`));
   184â†’  }
   185â†’
   186â†’  if (result.warnings.length > 0) {
   187â†’    console.error('[ISCValidator] WARNINGS:');
   188â†’    result.warnings.forEach((w) => console.error(`  âš ď¸Ź  ${w}`));
   189â†’  }
   190â†’
   191â†’  // Check if OBSERVE phase was attempted (algorithm was run)
   192â†’  const responseText = parsed.plainCompletion || '';
   193â†’  const algorithmAttempted = responseText.includes('OBSERVE') ||
   194â†’                              responseText.includes('đź“¦ CAPABILITIES') ||
   195â†’                              responseText.includes('ISC TRACKER');
   196â†’
   197â†’  // BLOCKING LOGIC: If algorithm was attempted but ISC is empty, block
   198â†’  const isc = readISC(taskPath);
   199â†’  if (algorithmAttempted && isc && (!isc.criteria || isc.criteria.length === 0)) {
   200â†’    result.shouldBlock = true;
   201â†’    result.blockReason = `ISC.json criteria array is EMPTY after algorithm execution.
   202â†’
   203â†’You attempted the algorithm but did not populate ISC criteria.
