    61â†’const STATE_DIR = join(MEMORY_DIR, 'STATE');
    62â†’const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    63â†’const WORK_DIR = join(MEMORY_DIR, 'WORK');
