    88â†’function parseYaml(content: string): WorkMeta {
    89â†’  // Simple YAML parser for our specific format
    90â†’  const meta: any = {};
    91â†’  const lines = content.split('\n');
    92â†’  let currentKey = '';
    93â†’  let inArray = false;
    94â†’  let arrayKey = '';
    95â†’
    96â†’  for (const line of lines) {
    97â†’    const trimmed = line.trim();
    98â†’    if (!trimmed || trimmed.startsWith('#')) continue;
    99â†’
   100â†’    // Handle array items
   101â†’    if (trimmed.startsWith('- ') && inArray) {
   102â†’      const value = trimmed.slice(2).replace(/^["']|["']$/g, '');
   103â†’      if (arrayKey === 'lineage') {
   104â†’        // Nested array in lineage
   105â†’        const lastKey = Object.keys(meta.lineage).pop();
   106â†’        if (lastKey) meta.lineage[lastKey].push(value);
   107â†’      } else {
   108â†’        meta[arrayKey].push(value);
   109â†’      }
   110â†’      continue;
   111â†’    }
   112â†’
   113â†’    // Handle key: value pairs
   114â†’    const match = trimmed.match(/^([a-z_]+):\s*(.*)$/);
   115â†’    if (match) {
   116â†’      const [, key, value] = match;
   117â†’      currentKey = key;
   118â†’
   119â†’      if (key === 'lineage') {
   120â†’        meta.lineage = { tools_used: [], files_changed: [], agents_spawned: [] };
   121â†’        inArray = false;
   122â†’        continue;
   123â†’      }
   124â†’
   125â†’      if (value === '[]') {
   126â†’        if (meta.lineage) {
   127â†’          meta.lineage[key] = [];
   128â†’        } else {
   129â†’          meta[key] = [];
   130â†’        }
   131â†’        inArray = false;
   132â†’      } else if (value === '') {
   133â†’        if (meta.lineage && ['tools_used', 'files_changed', 'agents_spawned'].includes(key)) {
   134â†’          meta.lineage[key] = [];
   135â†’          arrayKey = 'lineage';
   136â†’          inArray = true;
   137â†’        } else {
   138â†’          meta[key] = [];
   139â†’          arrayKey = key;
   140â†’          inArray = true;
   141â†’        }
   142â†’      } else {
   143â†’        const cleanValue = value.replace(/^["']|["']$/g, '');
   144â†’        if (meta.lineage && ['tools_used', 'files_changed', 'agents_spawned'].includes(key)) {
   145â†’          meta.lineage[key] = cleanValue === 'null' ? [] : [cleanValue];
   146â†’        } else {
   147â†’          meta[key] = cleanValue === 'null' ? null : cleanValue;
   148â†’        }
   149â†’        inArray = false;
   150â†’      }
   151â†’    }
   152â†’  }
   153â†’
   154â†’  return meta as WorkMeta;
   155â†’}
