   157â†’function getMonthDir(category: 'SYSTEM' | 'ALGORITHM'): string {
   158â†’  const now = new Date();
   159â†’  const year = now.getFullYear();
   160â†’  const month = String(now.getMonth() + 1).padStart(2, '0');
   161â†’
   162â†’  const monthDir = join(LEARNING_DIR, category, `${year}-${month}`);
   163â†’
   164â†’  if (!existsSync(monthDir)) {
