   171â†’function writeLearning(workMeta: WorkMeta, idealContent: string): void {
   172â†’  const category = getLearningCategory(workMeta.title);
   173â†’  const monthDir = getMonthDir(category);
   174â†’
   175â†’  const dateStr = getPSTDate();
   176â†’  const timeStr = new Date().toISOString().split('T')[1].slice(0, 5).replace(':', '');
   177â†’  const titleSlug = workMeta.title
   178â†’    .toLowerCase()
   179â†’    .replace(/[^a-z0-9]+/g, '-')
   180â†’    .slice(0, 30);
   181â†’
   182â†’  const filename = `${dateStr}_${timeStr}_work_${titleSlug}.md`;
   183â†’  const filepath = join(monthDir, filename);
   184â†’
   185â†’  // Don't overwrite existing learnings
   186â†’  if (existsSync(filepath)) {
   187â†’    console.error(`[WorkCompletionLearning] Learning already exists: ${filename}`);
   188â†’    return;
   189â†’  }
   190â†’
   191â†’  // Calculate session duration
   192â†’  let duration = 'Unknown';
   193â†’  if (workMeta.created_at && workMeta.completed_at) {
   194â†’    const start = new Date(workMeta.created_at);
   195â†’    const end = new Date(workMeta.completed_at);
   196â†’    const minutes = Math.round((end.getTime() - start.getTime()) / 60000);
   197â†’    if (minutes < 60) {
   198â†’      duration = `${minutes} minutes`;
   199â†’    } else {
   200â†’      const hours = Math.floor(minutes / 60);
   201â†’      const mins = minutes % 60;
   202â†’      duration = `${hours}h ${mins}m`;
   203â†’    }
   204â†’  }
   205â†’
   206â†’  const content = `# Work Completion Learning
   207â†’
   208â†’**Title:** ${workMeta.title}
   209â†’**Duration:** ${duration}
   210â†’**Category:** ${category}
   211â†’**Session:** ${workMeta.session_id}
   212â†’
   213â†’---
   214â†’
   215â†’## Ideal State Criteria
   216â†’
   217â†’${idealContent || 'Not specified'}
   218â†’
   219â†’## What Was Done
   220â†’
   221â†’- **Files Changed:** ${workMeta.lineage?.files_changed?.length || 0}
   222â†’- **Tools Used:** ${workMeta.lineage?.tools_used?.join(', ') || 'None tracked'}
   223â†’- **Agents Spawned:** ${workMeta.lineage?.agents_spawned?.length || 0}
   224â†’
   225â†’## Insights
   226â†’
   227â†’*This work session completed successfully. Consider what made it effective:*
   228â†’
   229â†’- Was the approach straightforward or did it require iteration?
   230â†’- Were there any blockers or surprises?
   231â†’- What patterns from this work apply to future tasks?
   232â†’
   233â†’---
   234â†’
   235â†’*Auto-captured by WorkCompletionLearning hook at session end*
   236â†’`;
   237â†’
   238â†’  writeFileSync(filepath, content);
   239â†’  console.error(`[WorkCompletionLearning] Created learning: ${filename}`);
   240â†’}
