   297â†’        }
   298â†’      } catch {
   299â†’        // Ignore parse errors
   300â†’      }
   301â†’    }
   302â†’
   303â†’    // Check if this was significant work (has files changed or was manually created)
   304â†’    const hasSignificantWork = (
   305â†’      (workMeta.lineage?.files_changed?.length || 0) > 0 ||
