   314â†’    }
   315â†’
   316â†’    process.exit(0);
   317â†’  } catch (error) {
   318â†’    // Silent failure - don't disrupt workflow
   319â†’    console.error(`[WorkCompletionLearning] Error: ${error}`);
   320â†’    process.exit(0);
   321â†’  }
   322â†’}
   323â†’
