    83â†’async function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    84â†’  return new Promise((resolve, reject) => {
    85â†’    let data = '';
    86â†’    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    87â†’    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    88â†’    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    89â†’    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
    90â†’  });
    91â†’}
    92â†’
    93â†’/**
    94â†’ * CRITICAL: Precise rating detection
    95â†’ *
    96â†’ * Must match:
    97â†’ * - "7" (single number)
    98â†’ * - "8 - good work" (number + dash + comment)
    99â†’ * - "6: needs work" (number + colon + comment)
   100â†’ * - "9 excellent" (number + space + comment)
   101â†’ *
   102â†’ * Must NOT match:
   103â†’ * - "I have 7 items" (number in sentence)
   104â†’ * - "do step 7" (contextual number)
   105â†’ * - "7th thing" (ordinal)
   106â†’ */
   107â†’function parseRating(prompt: string): { rating: number; comment?: string } | null {
   108â†’  const trimmed = prompt.trim();
   109â†’
   110â†’  // Pattern: Start with single digit (1-10), optionally followed by separator and comment
   111â†’  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   112â†’
   113â†’  const match = trimmed.match(ratingPattern);
   114â†’  if (!match) return null;
   115â†’
   116â†’  const rating = parseInt(match[1], 10);
   117â†’  const comment = match[2]?.trim() || undefined;
   118â†’
   119â†’  if (rating < 1 || rating > 10) return null;
   120â†’
   121â†’  // Reject if comment starts with common words that indicate a sentence
   122â†’  if (comment) {
   123â†’    const sentenceStarters = /^(items?|things?|steps?|files?|lines?|bugs?|issues?|errors?|times?|minutes?|hours?|days?|seconds?|percent|%|th\b|st\b|nd\b|rd\b|of\b|in\b|at\b|to\b|the\b|a\b|an\b)/i;
   124â†’    if (sentenceStarters.test(comment)) {
   125â†’      return null;
   126â†’    }
   127â†’  }
   128â†’
   129â†’  return { rating, comment };
   130â†’}
