   151â†’/**
   152â†’ * Extract last response summary from transcript for learning context
   153â†’ */
   154â†’function getLastResponseSummary(transcriptPath: string): string {
   155â†’  try {
   156â†’    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   157â†’
   158â†’    const content = readFileSync(transcriptPath, 'utf-8');
   159â†’    const lines = content.trim().split('\n');
   160â†’
   161â†’    let lastAssistant = '';
   162â†’    for (const line of lines) {
   163â†’      try {
   164â†’        const entry = JSON.parse(line);
   165â†’        if (entry.type === 'assistant' && entry.message?.content) {
   166â†’          const text = typeof entry.message.content === 'string'
   167â†’            ? entry.message.content
   168â†’            : Array.isArray(entry.message.content)
   169â†’              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   170â†’              : '';
   171â†’          if (text) lastAssistant = text;
   172â†’        }
   173â†’      } catch { /* skip invalid lines */ }
   174â†’    }
   175â†’
   176â†’    const summaryMatch = lastAssistant.match(/SUMMARY:\s*([^\n]+)/i);
   177â†’    return summaryMatch ? summaryMatch[1].trim() : lastAssistant.slice(0, 500);
   178â†’  } catch {
   179â†’    return '';
   180â†’  }
   181â†’}
