   183â†’/**
   184â†’ * Capture low rating as learning opportunity
   185â†’ */
   186â†’function captureLowRatingLearning(rating: number, comment: string | undefined, responseContext: string): void {
   187â†’  if (rating >= 6) return;
   188â†’
   189â†’  const baseDir = getPaiDir();
   190â†’  const { year, month, day, hours, minutes, seconds } = getPSTComponents();
   191â†’
   192â†’  const yearMonth = `${year}-${month}`;
   193â†’  const category = getLearningCategory(responseContext, comment);
   194â†’  const learningsDir = join(baseDir, 'MEMORY', 'LEARNING', category, yearMonth);
   195â†’
   196â†’  if (!existsSync(learningsDir)) {
   197â†’    mkdirSync(learningsDir, { recursive: true });
   198â†’  }
   199â†’
   200â†’  const filename = `${year}-${month}-${day}-${hours}${minutes}${seconds}_LEARNING_low-rating-${rating}.md`;
   201â†’  const filepath = join(learningsDir, filename);
   202â†’
   203â†’  const content = `---
   204â†’capture_type: LEARNING
   205â†’timestamp: ${year}-${month}-${day} ${hours}:${minutes}:${seconds} PST
   206â†’rating: ${rating}
   207â†’auto_captured: true
   208â†’tags: [low-rating, improvement-opportunity]
   209â†’---
   210â†’
   211â†’# Low Rating Captured: ${rating}/10
   212â†’
   213â†’**Date:** ${year}-${month}-${day}
   214â†’**Rating:** ${rating}/10
   215â†’${comment ? `**Feedback:** ${comment}` : ''}
   216â†’
   217â†’---
   218â†’
   219â†’## Response Context
   220â†’
   221â†’${responseContext || 'No response context available'}
   222â†’
   223â†’---
   224â†’
   225â†’## Improvement Notes
   226â†’
   227â†’This response was rated ${rating}/10 by ${getPrincipalName()}. Use this as an improvement opportunity.
   228â†’
   229â†’${comment ? `**${getPrincipalName()}'s feedback:** ${comment}` : ''}
   230â†’
   231â†’---
   232â†’`;
   233â†’
   234â†’  writeFileSync(filepath, content, 'utf-8');
   235â†’  console.error(`[ExplicitRatingCapture] Captured low rating learning to ${filepath}`);
   236â†’}
