   245â†’async function classifyPrompt(prompt: string, hasExistingSession: boolean): Promise<PromptClassification> {
   246â†’  const trimmed = prompt.trim();
   247â†’
   248â†’  // Quick heuristics
   249â†’  if (trimmed.length < 15 && /^(yes|no|ok|okay|thanks|proceed|continue|go ahead|sure|got it)$/i.test(trimmed)) {
   250â†’    return { type: 'conversational', title: '', effort: 'TRIVIAL', is_new_topic: false };
   251â†’  }
   252â†’
   253â†’  // Use inference for classification
   254â†’  try {
   255â†’    const contextNote = hasExistingSession
   256â†’      ? '\n\nNOTE: There is an existing session with prior tasks. Consider if this is a continuation or new topic.'
   257â†’      : '\n\nNOTE: This is the first prompt in a new session. is_new_topic should be true.';
   258â†’
   259â†’    const result = await inference({
   260â†’      systemPrompt: CLASSIFICATION_PROMPT + contextNote,
   261â†’      userPrompt: prompt,
   262â†’      expectJson: true,
   263â†’      timeout: 10000,
   264â†’      level: 'fast',
   265â†’    });
   266â†’
   267â†’    if (result.success && result.parsed) {
   268â†’      const parsed = result.parsed as PromptClassification;
   269â†’      return {
   270â†’        type: parsed.type || 'work',
   271â†’        title: parsed.title || prompt.substring(0, 50),
   272â†’        effort: parsed.effort || 'STANDARD',
   273â†’        is_new_topic: hasExistingSession ? (parsed.is_new_topic ?? false) : true,
   274â†’      };
   275â†’    }
   276â†’  } catch (err) {
   277â†’    console.error(`[AutoWork] Classification failed: ${err}`);
   278â†’  }
   279â†’
   280â†’  // Fallback
   281â†’  return {
   282â†’    type: 'work',
   283â†’    title: prompt.substring(0, 50).replace(/[^a-zA-Z0-9\s]/g, '').trim(),
   284â†’    effort: 'STANDARD',
   285â†’    is_new_topic: !hasExistingSession,
   286â†’  };
   287â†’}
