   203â†’function getRecentContext(transcriptPath: string, maxTurns: number = 3): string {
   204â†’  try {
   205â†’    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   206â†’
   207â†’    const content = readFileSync(transcriptPath, 'utf-8');
   208â†’    const lines = content.trim().split('\n');
   209â†’
   210â†’    const turns: { role: string; text: string }[] = [];
   211â†’
   212â†’    for (const line of lines) {
   213â†’      if (!line.trim()) continue;
   214â†’      try {
   215â†’        const entry = JSON.parse(line);
   216â†’
   217â†’        if (entry.type === 'user' && entry.message?.content) {
   218â†’          let text = '';
   219â†’          if (typeof entry.message.content === 'string') {
   220â†’            text = entry.message.content;
   221â†’          } else if (Array.isArray(entry.message.content)) {
   222â†’            text = entry.message.content
   223â†’              .filter((c: any) => c.type === 'text')
   224â†’              .map((c: any) => c.text)
   225â†’              .join(' ');
   226â†’          }
   227â†’          if (text.trim()) {
   228â†’            turns.push({ role: 'User', text: text.slice(0, 200) });
   229â†’          }
   230â†’        }
   231â†’
   232â†’        if (entry.type === 'assistant' && entry.message?.content) {
   233â†’          const text = typeof entry.message.content === 'string'
   234â†’            ? entry.message.content
   235â†’            : Array.isArray(entry.message.content)
   236â†’              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   237â†’              : '';
   238â†’          if (text) {
   239â†’            const summaryMatch = text.match(/SUMMARY:\s*([^\n]+)/i);
   240â†’            const shortText = summaryMatch ? summaryMatch[1] : text.slice(0, 150);
   241â†’            turns.push({ role: 'Assistant', text: shortText });
   242â†’          }
   243â†’        }
   244â†’      } catch {}
   245â†’    }
   246â†’
   247â†’    const recentTurns = turns.slice(-maxTurns);
   248â†’    if (recentTurns.length === 0) return '';
   249â†’
   250â†’    return recentTurns.map(t => `${t.role}: ${t.text}`).join('\n');
   251â†’  } catch {
   252â†’    return '';
   253â†’  }
   254â†’}
