    88â†’async function findTaskResult(transcriptPath: string, maxAttempts: number = 2): Promise<{ result: string | null, agentType: string | null, description: string | null, toolInput: any | null }> {
    89â†’  console.error(`đź“‚ Looking for Task result in transcript: ${transcriptPath}`);
    90â†’
    91â†’  // If the provided transcript path doesn't exist, try to find the most recent agent transcript
    92â†’  let actualTranscriptPath = transcriptPath;
    93â†’
    94â†’  // PERFORMANCE FIX: Reduced from 6 attempts (10+ seconds) to 2 attempts (~500ms)
    95â†’  // The transcript should already exist when SubagentStop fires
    96â†’  // If it doesn't exist after a quick check, don't block - just exit gracefully
    97â†’  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    98â†’    if (attempt > 0) {
    99â†’      // Single short retry - 200ms is enough for filesystem sync
   100â†’      await delay(200);
   101â†’    }
   102â†’
   103â†’    if (!existsSync(actualTranscriptPath)) {
   104â†’      console.error(`âťŚ Transcript file doesn't exist: ${actualTranscriptPath} (attempt ${attempt + 1}/${maxAttempts})`);
   105â†’
   106â†’      // Try to find agent transcript in the same directory
   107â†’      const dir = require('path').dirname(transcriptPath);
   108â†’      if (existsSync(dir)) {
   109â†’        const { readdirSync, statSync } = require('fs');
   110â†’        const files = readdirSync(dir)
   111â†’          .filter((f: string) => f.startsWith('agent-') && f.endsWith('.jsonl'))
   112â†’          .map((f: string) => ({ name: f, mtime: statSync(join(dir, f)).mtime }))
   113â†’          .sort((a: any, b: any) => b.mtime - a.mtime);
   114â†’
   115â†’        if (files.length > 0) {
   116â†’          actualTranscriptPath = join(dir, files[0].name);
   117â†’          console.error(`đź”„ Found recent agent transcript: ${actualTranscriptPath}`);
   118â†’        }
   119â†’      }
   120â†’
   121â†’      if (!existsSync(actualTranscriptPath)) {
   122â†’        continue;
   123â†’      }
   124â†’    }
   125â†’
   126â†’    try {
   127â†’      const transcript = readFileSync(actualTranscriptPath, 'utf-8');
   128â†’      const lines = transcript.trim().split('\n');
   129â†’
   130â†’      // Search from the end of the transcript backwards
   131â†’      for (let i = lines.length - 1; i >= 0; i--) {
   132â†’        try {
   133â†’          const entry = JSON.parse(lines[i]);
   134â†’
   135â†’          // Look for assistant messages that contain Task tool_use
   136â†’          if (entry.type === 'assistant' && entry.message?.content) {
   137â†’            for (const content of entry.message.content) {
   138â†’              if (content.type === 'tool_use' && content.name === 'Task') {
   139â†’                const toolInput = content.input;
   140â†’                const description = toolInput?.description || null;
   141â†’                console.error(`âś… Found Task invocation with subagent: ${toolInput?.subagent_type}, description: ${description}`);
   142â†’                // Found a Task invocation, now look for its result
   143â†’                // The result should be in a subsequent user message
   144â†’                for (let j = i + 1; j < lines.length; j++) {
   145â†’                  const resultEntry = JSON.parse(lines[j]);
   146â†’                  if (resultEntry.type === 'user' && resultEntry.message?.content) {
   147â†’                    for (const resultContent of resultEntry.message.content) {
   148â†’                      if (resultContent.type === 'tool_result' && resultContent.tool_use_id === content.id) {
   149â†’                        // Found the matching Task result
   150â†’                        // Content can be either a string or an array of objects with text
   151â†’                        let taskOutput: string;
   152â†’                        if (typeof resultContent.content === 'string') {
   153â†’                          taskOutput = resultContent.content;
   154â†’                        } else if (Array.isArray(resultContent.content)) {
   155â†’                          // Extract text from array of content objects
   156â†’                          taskOutput = resultContent.content
   157â†’                            .filter((item: any) => item.type === 'text')
   158â†’                            .map((item: any) => item.text)
   159â†’                            .join('\n');
   160â†’                        } else {
   161â†’                          console.error('âťŚ Unexpected tool_result content type');
   162â†’                          continue;
   163â†’                        }
   164â†’
   165â†’                        // Extract agent type from the output
   166â†’                        let agentType = 'default';
   167â†’                        const agentMatch = taskOutput.match(/Sub-agent\s+(\w+)\s+completed/i);
   168â†’                        if (agentMatch) {
