   170â†’                        }
   171â†’
   172â†’                        return { result: taskOutput, agentType, description, toolInput };
   173â†’                      }
   174â†’                    }
   175â†’                  }
   176â†’                }
   177â†’              }
   178â†’            }
   179â†’          }
   180â†’        } catch (e) {
   181â†’          // Invalid JSON line, skip
   182â†’        }
   183â†’      }
   184â†’    } catch (e) {
