   197â†’  // Look for the COMPLETED section in the agent's output
   198â†’  // Priority: 1) New đź—Łď¸Ź format, 2) Legacy [AGENT:type] format
   199â†’  const agentPatterns = [
   200â†’    // NEW FORMAT: đź—Łď¸Ź AgentName: [text] (primary)
   201â†’    // Captures agent name dynamically from the line
   202â†’    /đź—Łď¸Ź\s*\*{0,2}([\w-]+):?\*{0,2}\s*(.+?)(?:\n|$)/is,
   203â†’
   204â†’    // LEGACY FORMAT: đźŽŻ COMPLETED: [AGENT:type] [text] (backward compatibility)
