   209â†’    /đźŽŻ\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   210â†’    /COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   211â†’
   212â†’    // Multi-line patterns (emoji/COMPLETED on one line, AGENT tag on next)
   213â†’    /đźŽŻ\s*COMPLETED[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
