   215â†’    /\*+đźŽŻ\s*COMPLETED\*+[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   216â†’
   217â†’    // Generic pattern for current format
   218â†’    /đźŽŻ.*COMPLETED.*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   219â†’
   220â†’    // OLD: Handle legacy "I completed" format (for backward compatibility)
   221â†’    /\*+đźŽŻ\s*COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   222â†’    /\*+đźŽŻ\s+COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   223â†’    /đźŽŻ\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
