   459â†’    .replace(/ PST$/, '')
   460â†’    .replace(/:/g, '')
   461â†’    .replace(/ /, '-'); // YYYY-MM-DD-HHMMSS
   462â†’
   463â†’  const yearMonth = timestamp.substring(0, 7); // YYYY-MM
