    50â†’import { writeFileSync, existsSync, readFileSync, unlinkSync } from 'fs';
    51â†’import { join } from 'path';
    52â†’import { getISOTimestamp } from './lib/time';
    53â†’import { getPaiDir } from './lib/paths';
    54â†’
    55â†’// Cross-platform path resolution
    56â†’const PAI_DIR = getPaiDir();
    57â†’const MEMORY_DIR = join(PAI_DIR, 'MEMORY');
    58â†’const STATE_DIR = join(MEMORY_DIR, 'STATE');
    59â†’const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    60â†’const WORK_DIR = join(MEMORY_DIR, 'WORK');
    61â†’
    62â†’interface CurrentWork {
    63â†’  session_id: string;
    64â†’  work_dir: string;
    65â†’  created_at: string;
    66â†’  item_count: number;
    67â†’}
    68â†’
    69â†’/**
    70â†’ * Mark work directory as completed and clear session state
    71â†’ */
    72â†’function clearSessionWork(): void {
    73â†’  try {
    74â†’    if (!existsSync(CURRENT_WORK_FILE)) {
    75â†’      console.error('[SessionSummary] No current work to complete');
    76â†’      return;
    77â†’    }
    78â†’
    79â†’    // Read current work state
    80â†’    const content = readFileSync(CURRENT_WORK_FILE, 'utf-8');
    81â†’    const currentWork: CurrentWork = JSON.parse(content);
    82â†’
    83â†’    // Mark work directory as COMPLETED
    84â†’    if (currentWork.work_dir) {
    85â†’      const metaPath = join(WORK_DIR, currentWork.work_dir, 'META.yaml');
    86â†’      if (existsSync(metaPath)) {
    87â†’        let metaContent = readFileSync(metaPath, 'utf-8');
    88â†’        metaContent = metaContent.replace(/^status: "ACTIVE"$/m, 'status: "COMPLETED"');
    89â†’        metaContent = metaContent.replace(/^completed_at: null$/m, `completed_at: "${getISOTimestamp()}"`);
    90â†’        writeFileSync(metaPath, metaContent, 'utf-8');
    91â†’        console.error(`[SessionSummary] Marked work directory as COMPLETED: ${currentWork.work_dir}`);
    92â†’      }
    93â†’    }
    94â†’
    95â†’    // Delete state file
    96â†’    unlinkSync(CURRENT_WORK_FILE);
    97â†’    console.error('[SessionSummary] Cleared session work state');
    98â†’  } catch (error) {
    99â†’    console.error(`[SessionSummary] Error clearing session work: ${error}`);
   100â†’  }
   101â†’}
   102â†’
   103â†’async function main() {
   104â†’  try {
   105â†’    // Read input from stdin (not strictly needed but matches hook pattern)
   106â†’    const input = await Bun.stdin.text();
   107â†’    if (!input || input.trim() === '') {
   108â†’      process.exit(0);
   109â†’    }
   110â†’
   111â†’    // Mark work as complete and clear state
   112â†’    // NOTE: Does NOT write to SESSIONS/ - WORK/ is the primary system
   113â†’    clearSessionWork();
   114â†’
   115â†’    console.error('[SessionSummary] Session ended, work marked complete');
   116â†’    process.exit(0);
   117â†’  } catch (error) {
   118â†’    // Silent failure - don't disrupt workflow
   119â†’    console.error(`[SessionSummary] SessionEnd hook error: ${error}`);
   120â†’    process.exit(0);
   121â†’  }
   122â†’}
   123â†’
   124â†’main();
