    70â†’function extractEffortLevel(text: string): EffortLevel | null {
    71â†’  const match = text.match(/level\s+(QUICK|STANDARD|THOROUGH|TRIVIAL)/i);
    72â†’  return match ? (match[1].toUpperCase() as EffortLevel) : null;
    73â†’}
    74â†’
    75â†’function extractISCSatisfaction(text: string): ISCDocument['satisfaction'] | null {
    76â†’  // Match patterns like "6 ISC criteria, all satisfied"
    77â†’  const allSatisfied = text.match(/(\d+)\s*(?:ISC\s*)?criteria?,?\s*all\s*satisfied/i);
    78â†’  if (allSatisfied) {
    79â†’    const total = parseInt(allSatisfied[1], 10);
    80â†’    return { satisfied: total, partial: 0, failed: 0, total };
    81â†’  }
    82â†’
    83â†’  // Match: X/Y criteria satisfied
    84â†’  const partial = text.match(/(\d+)\/(\d+)\s*criteria\s*satisfied/i);
    85â†’  if (partial) {
    86â†’    return {
    87â†’      satisfied: parseInt(partial[1], 10),
    88â†’      total: parseInt(partial[2], 10),
    89â†’      partial: 0,
    90â†’      failed: 0,
    91â†’    };
    92â†’  }
    93â†’
    94â†’  return null;
    95â†’}
