   104â†’function updateTaskISC(sessionDir: string, currentTask: string, text: string): void {
   105â†’  const taskPath = join(WORK_DIR, sessionDir, 'tasks', currentTask);
   106â†’  const iscPath = join(taskPath, 'ISC.json');
   107â†’
   108â†’  if (!existsSync(iscPath)) {
   109â†’    console.error(`[ISC] Task ISC.json not found: ${iscPath}`);
   110â†’    return;
   111â†’  }
   112â†’
   113â†’  try {
   114â†’    const doc: ISCDocument = JSON.parse(readFileSync(iscPath, 'utf-8'));
   115â†’    const timestamp = getISOTimestamp();
   116â†’
   117â†’    // Extract effort level if found
   118â†’    const effort = extractEffortLevel(text);
   119â†’    if (effort) {
   120â†’      doc.effortLevel = effort;
   121â†’    }
   122â†’
   123â†’    // Extract satisfaction from response
   124â†’    const satisfaction = extractISCSatisfaction(text);
   125â†’    if (satisfaction) {
   126â†’      doc.satisfaction = satisfaction;
   127â†’      doc.status = satisfaction.satisfied === satisfaction.total ? 'COMPLETE' : 'PARTIAL';
   128â†’    }
   129â†’
   130â†’    // Check for completion marker
   131â†’    if (text.includes('âś“ COMPLETE')) {
   132â†’      doc.status = 'COMPLETE';
   133â†’    }
   134â†’
   135â†’    doc.updatedAt = timestamp;
   136â†’
   137â†’    writeFileSync(iscPath, JSON.stringify(doc, null, 2), 'utf-8');
   138â†’    console.error(`[ISC] Updated task ISC: ${currentTask}`);
   139â†’  } catch (err) {
   140â†’    console.error(`[ISC] Error updating task ISC: ${err}`);
   141â†’  }
   142â†’}
