   163â†’
   164â†’      // Add completedAt if not present in frontmatter
   165â†’      if (!content.includes('completedAt:')) {
   166â†’        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1completedAt: "${timestamp}"\n$2`);
   167â†’      }
   168â†’
   169â†’      // Add summary if not present in frontmatter
   170â†’      const summary = (structured.completed || structured.summary || '').substring(0, 200);
   171â†’      if (summary && !content.includes('summary:')) {
   172â†’        content = content.replace(/^(---\n[\s\S]*?)(---)/, `$1summary: "${summary.replace(/"/g, '\\"')}"\n$2`);
   173â†’      }
