   187â†’function generateFilename(description: string, type: 'LEARNING' | 'WORK'): string {
   188â†’  const pstTimestamp = getPSTTimestamp();
   189â†’  const date = pstTimestamp.slice(0, 10);
   190â†’  const time = pstTimestamp.slice(11, 19).replace(/:/g, '');
   191â†’
   192â†’  const cleanDesc = description
   193â†’    .toLowerCase()
   194â†’    .replace(/[^a-z0-9\s-]/g, '')
   195â†’    .replace(/\s+/g, '-')
   196â†’    .slice(0, 60);
   197â†’
   198â†’  return `${date}-${time}_${type}_${cleanDesc}.md`;
