   255â†’function readCurrentWork(): CurrentWork | null {
   256â†’  try {
   257â†’    if (!existsSync(CURRENT_WORK_FILE)) return null;
   258â†’    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
   259â†’  } catch {
