   264â†’async function captureWorkSummary(text: string, structured: StructuredResponse): Promise<void> {
   265â†’  try {
   266â†’    const currentWork = readCurrentWork();
   267â†’
   268â†’    if (currentWork?.session_dir && currentWork?.current_task) {
   269â†’      // Update task ISC with satisfaction data
   270â†’      updateTaskISC(currentWork.session_dir, currentWork.current_task, text);
   271â†’
   272â†’      // Update task META if we have completion info
   273â†’      if (structured.summary || structured.completed) {
   274â†’        updateTaskMeta(currentWork.session_dir, currentWork.current_task, structured);
   275â†’      }
   276â†’    }
   277â†’
   278â†’    // Learning capture (unchanged)
   279â†’    const isLearning = isLearningCapture(text, structured.summary, structured.analysis);
   280â†’
   281â†’    if (isLearning) {
   282â†’      let description = (structured.completed || structured.summary || 'task-completion')
   283â†’        .replace(/^Completed\s+/i, '')
   284â†’        .replace(/\[AGENT:\w+\]\s*/gi, '')
   285â†’        .replace(/\[.*?\]/g, '')
   286â†’        .trim();
   287â†’
   288â†’      if (!description || description.length < 3) {
   289â†’        description = structured.summary || structured.analysis || 'task-completion';
   290â†’        description = description.replace(/^Completed\s+/i, '').trim();
   291â†’      }
   292â†’
   293â†’      if (!description || description.length < 3) {
   294â†’        description = 'general-task';
   295â†’      }
   296â†’
   297â†’      const yearMonth = getYearMonth();
   298â†’      const filename = generateFilename(description, 'LEARNING');
   299â†’      const category = getLearningCategory(text);
   300â†’      const targetDir = join(BASE_DIR, 'MEMORY', 'LEARNING', category, yearMonth);
   301â†’
   302â†’      if (!existsSync(targetDir)) {
   303â†’        mkdirSync(targetDir, { recursive: true });
   304â†’      }
   305â†’
   306â†’      const filePath = join(targetDir, filename);
   307â†’      const timestamp = getPSTTimestamp();
   308â†’      const content = generateLearningContent(structured, text, timestamp);
   309â†’
   310â†’      writeFileSync(filePath, content, 'utf-8');
   311â†’      console.log(`âś… Captured learning to: ${filePath}`);
   312â†’    }
   313â†’  } catch (error) {
   314â†’    console.error('[Capture] Error capturing work summary:', error);
   315â†’  }
   316â†’}
