   318â†’/**
   319â†’ * Handle response capture with pre-parsed transcript data.
   320â†’ */
   321â†’export async function handleCapture(parsed: ParsedTranscript, hookInput: HookInput): Promise<void> {
   322â†’  const { lastMessage, structured, plainCompletion } = parsed;
   323â†’
   324â†’  // Capture work summary (async, non-blocking)
   325â†’  if (lastMessage) {
   326â†’    captureWorkSummary(lastMessage, structured).catch(err => {
   327â†’      console.error('[Capture] History capture failed (non-critical):', err);
   328â†’    });
   329â†’  }
   330â†’
   331â†’  // Push notifications for long tasks
   332â†’  const duration = getSessionDurationMinutes();
   333â†’  if (duration > 0) {
   334â†’    console.error(`âŹ±ď¸Ź Session duration: ${duration.toFixed(1)} minutes`);
   335â†’  }
   336â†’
   337â†’  const hasError = lastMessage && (
   338â†’    /error|failed|exception|crash/i.test(lastMessage) &&
   339â†’    /đź“Š\s*STATUS:.*(?:error|failed|broken)/i.test(lastMessage)
   340â†’  );
   341â†’
   342â†’  if (hasError) {
   343â†’    notifyError(plainCompletion).catch(() => {});
   344â†’  } else {
   345â†’    notifyTaskComplete(plainCompletion).catch(() => {});
   346â†’  }
   347â†’
   348â†’  // Observability event
   349â†’  await sendEventToObservability({
   350â†’    source_app: getSourceApp(),
   351â†’    session_id: hookInput.session_id,
   352â†’    hook_event_type: 'Stop',
   353â†’    timestamp: getCurrentTimestamp(),
   354â†’    transcript_path: hookInput.transcript_path,
   355â†’    summary: structured.completed || plainCompletion,
   356â†’  }).catch(() => {});
   357â†’}
