     1â†’/**
     2â†’ * UpdateCounts.ts - Update settings.json with fresh system counts
     3â†’ *
     4â†’ * PURPOSE:
     5â†’ * Updates the counts section of settings.json at the end of each session.
     6â†’ * Banner and statusline then read from settings.json (instant, no execution).
     7â†’ *
     8â†’ * ARCHITECTURE:
     9â†’ * Stop hook â†’ UpdateCounts â†’ settings.json
    10â†’ * Session start â†’ Banner reads settings.json (instant)
    11â†’ * Session start â†’ Statusline reads settings.json (instant)
    12â†’ *
    13â†’ * This design ensures:
    14â†’ * - No spawning/execution at session start
    15â†’ * - Counts are always available (no waiting)
    16â†’ * - Single source of truth in settings.json
    17â†’ */
    18â†’
    19â†’import { readFileSync, writeFileSync, readdirSync, existsSync, statSync } from 'fs';
    20â†’import { join } from 'path';
    21â†’import { getPaiDir, getSettingsPath } from '../lib/paths';
    22â†’
    23â†’interface Counts {
    24â†’  skills: number;
    25â†’  workflows: number;
    26â†’  hooks: number;
    27â†’  signals: number;
    28â†’  files: number;
    29â†’  updatedAt: string;
    30â†’}
    31â†’
    32â†’/**
    33â†’ * Count files matching criteria recursively
    34â†’ */
    35â†’function countFilesRecursive(dir: string, extension?: string): number {
    36â†’  let count = 0;
    37â†’  try {
    38â†’    for (const entry of readdirSync(dir, { withFileTypes: true })) {
    39â†’      const fullPath = join(dir, entry.name);
    40â†’      if (entry.isDirectory()) {
    41â†’        count += countFilesRecursive(fullPath, extension);
    42â†’      } else if (entry.isFile()) {
    43â†’        if (!extension || entry.name.endsWith(extension)) {
    44â†’          count++;
    45â†’        }
    46â†’      }
    47â†’    }
    48â†’  } catch {
    49â†’    // Directory doesn't exist or not readable
    50â†’  }
    51â†’  return count;
    52â†’}
    53â†’
    54â†’/**
    55â†’ * Count .md files inside any Workflows directory
    56â†’ */
    57â†’function countWorkflowFiles(dir: string): number {
    58â†’  let count = 0;
    59â†’  try {
    60â†’    for (const entry of readdirSync(dir, { withFileTypes: true })) {
    61â†’      const fullPath = join(dir, entry.name);
    62â†’      if (entry.isDirectory()) {
    63â†’        if (entry.name.toLowerCase() === 'workflows') {
    64â†’          count += countFilesRecursive(fullPath, '.md');
    65â†’        } else {
    66â†’          count += countWorkflowFiles(fullPath);
    67â†’        }
    68â†’      }
    69â†’    }
    70â†’  } catch {
    71â†’    // Directory doesn't exist or not readable
    72â†’  }
    73â†’  return count;
    74â†’}
    75â†’
    76â†’/**
    77â†’ * Count skills (directories with SKILL.md file)
    78â†’ */
    79â†’function countSkills(paiDir: string): number {
    80â†’  let count = 0;
    81â†’  const skillsDir = join(paiDir, 'skills');
    82â†’  try {
    83â†’    for (const entry of readdirSync(skillsDir, { withFileTypes: true })) {
    84â†’      if (entry.isDirectory()) {
    85â†’        const skillFile = join(skillsDir, entry.name, 'SKILL.md');
    86â†’        if (existsSync(skillFile)) {
    87â†’          count++;
    88â†’        }
    89â†’      }
    90â†’    }
    91â†’  } catch {
    92â†’    // skills directory doesn't exist
    93â†’  }
    94â†’  return count;
    95â†’}
    96â†’
    97â†’/**
    98â†’ * Count hooks (.ts files in hooks/ at depth 1)
    99â†’ */
   100â†’function countHooks(paiDir: string): number {
   101â†’  let count = 0;
   102â†’  const hooksDir = join(paiDir, 'hooks');
   103â†’  try {
   104â†’    for (const entry of readdirSync(hooksDir, { withFileTypes: true })) {
   105â†’      if (entry.isFile() && entry.name.endsWith('.ts')) {
   106â†’        count++;
   107â†’      }
   108â†’    }
   109â†’  } catch {
   110â†’    // hooks directory doesn't exist
   111â†’  }
   112â†’  return count;
   113â†’}
   114â†’
   115â†’/**
   116â†’ * Count non-empty lines in a JSONL file (signals = rating entries)
   117â†’ */
   118â†’function countRatingsLines(filePath: string): number {
   119â†’  try {
   120â†’    if (!existsSync(filePath) || !statSync(filePath).isFile()) return 0;
   121â†’    return readFileSync(filePath, 'utf-8').split('\n').filter(l => l.trim()).length;
   122â†’  } catch {
   123â†’    return 0;
   124â†’  }
   125â†’}
   126â†’
   127â†’/**
   128â†’ * Get all counts
   129â†’ */
   130â†’function getCounts(paiDir: string): Counts {
   131â†’  return {
   132â†’    skills: countSkills(paiDir),
   133â†’    workflows: countWorkflowFiles(join(paiDir, 'skills')),
   134â†’    hooks: countHooks(paiDir),
   135â†’    signals: countRatingsLines(join(paiDir, 'MEMORY/LEARNING/SIGNALS/ratings.jsonl')),
   136â†’    files: countFilesRecursive(join(paiDir, 'skills/PAI/USER')),
   137â†’    updatedAt: new Date().toISOString(),
   138â†’  };
   139â†’}
   140â†’
   141â†’/**
   142â†’ * Handler called by StopOrchestrator
   143â†’ */
   144â†’export async function handleUpdateCounts(): Promise<void> {
   145â†’  const paiDir = getPaiDir();
   146â†’  const settingsPath = getSettingsPath();
   147â†’
   148â†’  try {
   149â†’    // Get fresh counts
   150â†’    const counts = getCounts(paiDir);
   151â†’
   152â†’    // Read current settings
   153â†’    const settings = JSON.parse(readFileSync(settingsPath, 'utf-8'));
   154â†’
   155â†’    // Update counts section
   156â†’    settings.counts = counts;
   157â†’
   158â†’    // Write back
   159â†’    writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + '\n');
   160â†’
   161â†’    console.error(`[UpdateCounts] Updated settings.json: ${counts.skills} skills, ${counts.workflows} workflows, ${counts.hooks} hooks, ${counts.signals} signals, ${counts.files} files`);
   162â†’  } catch (error) {
   163â†’    console.error('[UpdateCounts] Failed to update counts:', error);
   164â†’    // Non-fatal - don't throw, let other handlers continue
   165â†’  }
   166â†’}
   167â†’
   168â†’// Allow running standalone to seed initial counts
   169â†’if (import.meta.main) {
   170â†’  handleUpdateCounts().then(() => process.exit(0));
   171â†’}
