    41â†’  | 'config_update'
    42â†’  | 'tool_update'
    43â†’  | 'multi_area';
    44â†’
    45â†’export interface IntegrityState {
    46â†’  last_run: string;
    47â†’  last_changes_hash: string;
    48â†’  cooldown_until: string | null;
    49â†’}
    50â†’
    51â†’// ============================================================================
    52â†’// Path Constants
    53â†’// ============================================================================
    54â†’
    55â†’const PAI_DIR = getPaiDir();
    56â†’const STATE_FILE = join(PAI_DIR, 'MEMORY', 'STATE', 'integrity-state.json');
    57â†’
    58â†’// Paths that are excluded from integrity checks
    59â†’const EXCLUDED_PATHS = [
    60â†’  'MEMORY/WORK/',
    61â†’  'MEMORY/LEARNING/',
    62â†’  'MEMORY/STATE/',
    63â†’  'scratch/',
    64â†’  'Plans/',
    65â†’  'projects/',
    66â†’  '.git/',
    67â†’  'node_modules/',
    68â†’  'ShellSnapshots/',
    69â†’];
    70â†’
    71â†’// High-priority paths that always warrant documentation
    72â†’const HIGH_PRIORITY_PATHS = [
    73â†’  'skills/PAI/SYSTEM/',
    74â†’  'skills/PAI/USER/',
    75â†’  'PAISYSTEMARCHITECTURE.md',
    76â†’  'SKILLSYSTEM.md',
    77â†’  'MEMORYSYSTEM.md',
    78â†’  'THEHOOKSYSTEM.md',
    79â†’  'THEDELEGATIONSYSTEM.md',
    80â†’  'THENOTIFICATIONSYSTEM.md',
    81â†’  'settings.json',
    82â†’];
    83â†’
    84â†’// Philosophical/architectural patterns in paths
    85â†’const PHILOSOPHICAL_PATTERNS = [
    86â†’  /PAI\/SYSTEM\//i,
    87â†’  /PAI\/USER\//i,
    88â†’  /ARCHITECTURE/i,
    89â†’  /PRINCIPLES/i,
    90â†’  /FOUNDING/i,
    91â†’  /IDENTITY/i,
    92â†’];
    93â†’
    94â†’// Structural change patterns
    95â†’const STRUCTURAL_PATTERNS = [
    96â†’  /\/SKILL\.md$/i,           // Skill definitions
    97â†’  /\/Workflows\//i,          // Workflow routing
    98â†’  /settings\.json$/i,        // Configuration
    99â†’  /frontmatter/i,            // Metadata changes
   100â†’];
   101â†’
   102â†’// ============================================================================
   103â†’// Transcript Parsing
   104â†’// ============================================================================
   105â†’
   106â†’/**
   107â†’ * Parse tool_use blocks from a transcript that modify files.
   108â†’ * Extracts Write, Edit, and MultiEdit operations.
   109â†’ */
   110â†’export function parseToolUseBlocks(transcriptPath: string): FileChange[] {
   111â†’  try {
   112â†’    if (!existsSync(transcriptPath)) {
   113â†’      console.error('[ChangeDetection] Transcript not found:', transcriptPath);
   114â†’      return [];
   115â†’    }
   116â†’
   117â†’    const content = readFileSync(transcriptPath, 'utf-8');
   118â†’    const lines = content.trim().split('\n');
   119â†’    const changes: FileChange[] = [];
   120â†’    const seenPaths = new Set<string>();
   121â†’
   122â†’    for (const line of lines) {
   123â†’      if (!line.trim()) continue;
   124â†’
   125â†’      try {
   126â†’        const entry = JSON.parse(line);
   127â†’
   128â†’        // Look for assistant messages with tool_use
   129â†’        if (entry.type === 'assistant' && entry.message?.content) {
   130â†’          const contentArray = Array.isArray(entry.message.content)
   131â†’            ? entry.message.content
   132â†’            : [];
   133â†’
   134â†’          for (const block of contentArray) {
   135â†’            if (block.type !== 'tool_use') continue;
   136â†’
   137â†’            const toolName = block.name;
   138â†’            const input = block.input || {};
   139â†’
   140â†’            // Handle Write, Edit, MultiEdit tools
   141â†’            if (toolName === 'Write' && input.file_path) {
   142â†’              const path = normalizeToRelativePath(input.file_path);
   143â†’              if (!seenPaths.has(path)) {
   144â†’                seenPaths.add(path);
   145â†’                changes.push(createFileChange('Write', path));
   146â†’              }
   147â†’            } else if (toolName === 'Edit' && input.file_path) {
   148â†’              const path = normalizeToRelativePath(input.file_path);
   149â†’              if (!seenPaths.has(path)) {
   150â†’                seenPaths.add(path);
   151â†’                changes.push(createFileChange('Edit', path));
   152â†’              }
   153â†’            } else if (toolName === 'MultiEdit' && input.edits) {
   154â†’              for (const edit of input.edits) {
   155â†’                if (edit.file_path) {
   156â†’                  const path = normalizeToRelativePath(edit.file_path);
   157â†’                  if (!seenPaths.has(path)) {
   158â†’                    seenPaths.add(path);
   159â†’                    changes.push(createFileChange('Edit', path));
   160â†’                  }
   161â†’                }
   162â†’              }
   163â†’            }
   164â†’          }
   165â†’        }
   166â†’      } catch {
   167â†’        // Skip invalid JSON lines
   168â†’      }
   169â†’    }
   170â†’
   171â†’    return changes;
   172â†’  } catch (error) {
   173â†’    console.error('[ChangeDetection] Error parsing transcript:', error);
   174â†’    return [];
   175â†’  }
   176â†’}
   177â†’
   178â†’/**
   179â†’ * Normalize an absolute path to relative (to PAI_DIR).
   180â†’ */
   181â†’function normalizeToRelativePath(absolutePath: string): string {
   182â†’  if (absolutePath.startsWith(PAI_DIR)) {
   183â†’    return relative(PAI_DIR, absolutePath);
   184â†’  }
   185â†’  return absolutePath;
   186â†’}
   187â†’
   188â†’/**
   189â†’ * Create a FileChange object with categorization.
   190â†’ */
   191â†’function createFileChange(tool: 'Write' | 'Edit', path: string): FileChange {
   192â†’  return {
   193â†’    tool,
   194â†’    path,
   195â†’    category: categorizeChange(path),
   196â†’    isPhilosophical: isPhilosophicalPath(path),
   197â†’    isStructural: isStructuralPath(path),
   198â†’  };
   199â†’}
   200â†’
   201â†’// ============================================================================
   202â†’// Change Categorization
   203â†’// ============================================================================
   204â†’
   205â†’/**
   206â†’ * Categorize a file path by its location in the PAI system.
   207â†’ */
   208â†’export function categorizeChange(path: string): ChangeCategory | null {
   209â†’  // Check exclusions first
   210â†’  for (const excluded of EXCLUDED_PATHS) {
   211â†’    if (path.includes(excluded)) {
   212â†’      return null;
   213â†’    }
   214â†’  }
   215â†’
   216â†’  // Check if path is within PAI directory
   217â†’  const absolutePath = path.startsWith('/') ? path : join(PAI_DIR, path);
   218â†’  if (!absolutePath.startsWith(PAI_DIR)) {
   219â†’    return null;
   220â†’  }
   221â†’
   222â†’  // Categorize by path pattern
   223â†’  if (path.includes('skills/')) {
   224â†’    if (path.includes('/Workflows/')) return 'workflow';
   225â†’    if (path.includes('PAI/SYSTEM/')) return 'core-system';
   226â†’    return 'skill';
   227â†’  }
   228â†’
   229â†’  if (path.includes('hooks/')) return 'hook';
   230â†’  if (path.includes('MEMORY/PAISYSTEMUPDATES/')) return 'documentation';
   231â†’  if (path.includes('MEMORY/')) return 'memory-system';
   232â†’  if (path.endsWith('settings.json')) return 'config';
   233â†’  if (path.endsWith('.md') && !path.includes('WORK/')) return 'documentation';
   234â†’
   235â†’  return null;
   236â†’}
   237â†’
   238â†’/**
   239â†’ * Check if a path represents philosophical/architectural content.
   240â†’ */
   241â†’function isPhilosophicalPath(path: string): boolean {
   242â†’  for (const pattern of PHILOSOPHICAL_PATTERNS) {
   243â†’    if (pattern.test(path)) return true;
   244â†’  }
   245â†’  for (const highPriority of HIGH_PRIORITY_PATHS) {
   246â†’    if (path.includes(highPriority)) return true;
   247â†’  }
   248â†’  return false;
   249â†’}
   250â†’
   251â†’/**
   252â†’ * Check if a path represents structural content (SKILL.md, workflows, config).
   253â†’ */
   254â†’function isStructuralPath(path: string): boolean {
   255â†’  for (const pattern of STRUCTURAL_PATTERNS) {
   256â†’    if (pattern.test(path)) return true;
   257â†’  }
   258â†’  return false;
   259â†’}
   260â†’
   261â†’// ============================================================================
   262â†’// Significance Detection
   263â†’// ============================================================================
   264â†’
   265â†’/**
   266â†’ * Determine if changes are significant enough to warrant background integrity check.
   267â†’ */
   268â†’export function isSignificantChange(changes: FileChange[]): boolean {
   269â†’  // Filter to only PAI system changes
   270â†’  const systemChanges = changes.filter(c => c.category !== null);
   271â†’
   272â†’  if (systemChanges.length === 0) return false;
   273â†’
   274â†’  // Always significant if philosophical or structural changes
   275â†’  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
   276â†’    return true;
   277â†’  }
   278â†’
   279â†’  // Significant if multiple files in same domain
   280â†’  const categories = new Set(systemChanges.map(c => c.category));
   281â†’  if (categories.size >= 1 && systemChanges.length >= 2) {
   282â†’    return true;
   283â†’  }
   284â†’
   285â†’  // Significant if any skill, hook, or core-system change
   286â†’  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'core-system', 'workflow'];
   287â†’  if (systemChanges.some(c => importantCategories.includes(c.category!))) {
   288â†’    return true;
   289â†’  }
   290â†’
   291â†’  return false;
   292â†’}
   293â†’
   294â†’/**
   295â†’ * Check if changes warrant documentation.
   296â†’ * UPDATED: Lower thresholds for more granular, frequent documentation.
   297â†’ * Philosophy: File system is cheap, more signal is valuable.
   298â†’ */
   299â†’export function shouldDocumentChanges(changes: FileChange[]): boolean {
   300â†’  const systemChanges = changes.filter(c => c.category !== null);
   301â†’
   302â†’  // No changes to document
   303â†’  if (systemChanges.length === 0) return false;
   304â†’
   305â†’  // Always document philosophical or structural changes
   306â†’  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
   307â†’    return true;
   308â†’  }
   309â†’
   310â†’  // Document ANY skill, hook, workflow, core-system, or config change
   311â†’  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'workflow', 'core-system', 'config'];
   312â†’  if (systemChanges.some(c => c.category && importantCategories.includes(c.category))) {
   313â†’    return true;
   314â†’  }
   315â†’
   316â†’  // Document if 2+ files changed (lowered from 3+)
   317â†’  if (systemChanges.length >= 2) {
   318â†’    return true;
   319â†’  }
   320â†’
   321â†’  // Document new file creation in system areas
   322â†’  const newFiles = systemChanges.filter(c => c.tool === 'Write');
   323â†’  if (newFiles.length > 0) return true;
   324â†’
   325â†’  // Document any tool file changes (.ts in Tools/)
   326â†’  if (systemChanges.some(c => c.path.includes('/Tools/') && c.path.endsWith('.ts'))) {
   327â†’    return true;
   328â†’  }
   329â†’
   330â†’  return false;
   331â†’}
   332â†’
   333â†’// ============================================================================
   334â†’// Throttling
   335â†’// ============================================================================
   336â†’
   337â†’// Reduced from 5 to 2 minutes for more frequent documentation updates
   338â†’const COOLDOWN_MINUTES = 2;
   339â†’
   340â†’/**
   341â†’ * Read the current integrity state.
   342â†’ */
   343â†’export function readIntegrityState(): IntegrityState | null {
   344â†’  try {
   345â†’    if (!existsSync(STATE_FILE)) return null;
   346â†’    const content = readFileSync(STATE_FILE, 'utf-8');
   347â†’    return JSON.parse(content);
   348â†’  } catch {
   349â†’    return null;
   350â†’  }
   351â†’}
   352â†’
   353â†’/**
   354â†’ * Check if we're within the cooldown period.
   355â†’ */
   356â†’export function isInCooldown(): boolean {
   357â†’  const state = readIntegrityState();
   358â†’  if (!state?.cooldown_until) return false;
   359â†’
   360â†’  const cooldownUntil = new Date(state.cooldown_until);
   361â†’  return new Date() < cooldownUntil;
   362â†’}
   363â†’
   364â†’/**
   365â†’ * Generate a hash of changes for deduplication.
   366â†’ */
   367â†’export function hashChanges(changes: FileChange[]): string {
   368â†’  const sorted = changes
   369â†’    .map(c => `${c.tool}:${c.path}`)
   370â†’    .sort()
   371â†’    .join('|');
   372â†’
   373â†’  // Simple hash
   374â†’  let hash = 0;
   375â†’  for (let i = 0; i < sorted.length; i++) {
   376â†’    const char = sorted.charCodeAt(i);
   377â†’    hash = ((hash << 5) - hash) + char;
   378â†’    hash = hash & hash;
   379â†’  }
   380â†’  return hash.toString(16);
   381â†’}
   382â†’
   383â†’/**
   384â†’ * Check if changes are duplicates of the last run.
   385â†’ */
   386â†’export function isDuplicateRun(changes: FileChange[]): boolean {
   387â†’  const state = readIntegrityState();
   388â†’  if (!state?.last_changes_hash) return false;
   389â†’
   390â†’  const currentHash = hashChanges(changes);
   391â†’  return currentHash === state.last_changes_hash;
   392â†’}
   393â†’
   394â†’/**
   395â†’ * Get the cooldown end time.
   396â†’ */
   397â†’export function getCooldownEndTime(): string {
   398â†’  const now = new Date();
   399â†’  now.setMinutes(now.getMinutes() + COOLDOWN_MINUTES);
   400â†’  return now.toISOString();
   401â†’}
   402â†’
   403â†’// ============================================================================
   404â†’// Significance and Change Type Determination
   405â†’// ============================================================================
   406â†’
   407â†’/**
   408â†’ * Determine the significance label based on change characteristics.
   409â†’ */
   410â†’export function determineSignificance(changes: FileChange[]): SignificanceLabel {
   411â†’  const count = changes.length;
   412â†’  const hasStructural = changes.some(c => c.isStructural);
   413â†’  const hasPhilosophical = changes.some(c => c.isPhilosophical);
   414â†’  const hasNewFiles = changes.some(c => c.tool === 'Write');
   415â†’
   416â†’  const categories = new Set(changes.map(c => c.category).filter(Boolean));
   417â†’  const hasCoreSystem = changes.some(c => c.category === 'core-system');
   418â†’  const hasHooks = changes.some(c => c.category === 'hook');
   419â†’  const hasSkills = changes.some(c => c.category === 'skill');
   420â†’
   421â†’  // Critical: breaking changes, major restructuring
   422â†’  if (hasStructural && hasPhilosophical && count >= 5) {
   423â†’    return 'critical';
   424â†’  }
   425â†’
   426â†’  // Major: new skills/workflows, architectural decisions
   427â†’  if (hasNewFiles && (hasStructural || hasPhilosophical)) {
   428â†’    return 'major';
   429â†’  }
   430â†’  if (hasCoreSystem || (categories.size >= 3)) {
   431â†’    return 'major';
   432â†’  }
   433â†’  if (hasHooks && count >= 3) {
   434â†’    return 'major';
   435â†’  }
   436â†’
   437â†’  // Moderate: multi-file updates, small features
   438â†’  if (count >= 3 || categories.size >= 2) {
   439â†’    return 'moderate';
   440â†’  }
   441â†’  if (hasSkills && count >= 2) {
   442â†’    return 'moderate';
   443â†’  }
   444â†’
   445â†’  // Minor: single file doc updates
   446â†’  if (count === 1 && !hasStructural && !hasPhilosophical) {
   447â†’    return 'minor';
   448â†’  }
   449â†’
   450â†’  // Trivial: only if very small doc changes
   451â†’  if (count === 1 && changes[0].category === 'documentation') {
   452â†’    return 'trivial';
   453â†’  }
   454â†’
   455â†’  return 'minor';
   456â†’}
   457â†’
   458â†’/**
   459â†’ * Determine the change type based on affected files.
   460â†’ */
   461â†’export function inferChangeType(changes: FileChange[]): ChangeType {
   462â†’  const categories = changes.map(c => c.category).filter(Boolean);
   463â†’  const uniqueCategories = new Set(categories);
   464â†’
   465â†’  // Multi-area if touching 3+ categories
   466â†’  if (uniqueCategories.size >= 3) {
   467â†’    return 'multi_area';
   468â†’  }
   469â†’
   470â†’  // Single category cases
   471â†’  if (uniqueCategories.size === 1) {
   472â†’    const cat = [...uniqueCategories][0];
   473â†’    switch (cat) {
   474â†’      case 'skill': return changes.some(c => c.isStructural) ? 'structure_change' : 'skill_update';
   475â†’      case 'hook': return 'hook_update';
   476â†’      case 'workflow': return 'workflow_update';
   477â†’      case 'config': return 'config_update';
   478â†’      case 'core-system': return 'structure_change';
   479â†’      case 'documentation': return 'doc_update';
   480â†’      default: return 'skill_update';
   481â†’    }
   482â†’  }
   483â†’
   484â†’  // Two categories - pick the more significant one
   485â†’  if (uniqueCategories.has('hook')) return 'hook_update';
   486â†’  if (uniqueCategories.has('skill')) return 'skill_update';
   487â†’  if (uniqueCategories.has('workflow')) return 'workflow_update';
   488â†’  if (uniqueCategories.has('config')) return 'config_update';
   489â†’
   490â†’  return 'multi_area';
   491â†’}
   492â†’
   493â†’/**
   494â†’ * Generate a descriptive 4-8 word title based on the changes.
   495â†’ */
   496â†’export function generateDescriptiveTitle(changes: FileChange[]): string {
   497â†’  const paths = changes.map(c => c.path);
   498â†’
   499â†’  // Extract skill names
   500â†’  const skillNames = new Set<string>();
   501â†’  for (const p of paths) {
   502â†’    const match = p.match(/skills\/([^/]+)\//);
   503â†’    if (match && match[1] !== 'PAI') skillNames.add(match[1]);
   504â†’  }
   505â†’
   506â†’  // Detect file types
   507â†’  const hasSkillMd = paths.some(p => p.endsWith('SKILL.md'));
   508â†’  const hasWorkflows = paths.some(p => p.includes('/Workflows/'));
   509â†’  const hasTools = paths.some(p => p.includes('/Tools/') && p.endsWith('.ts'));
   510â†’  const hasHooks = paths.some(p => p.includes('hooks/'));
   511â†’  const hasConfig = paths.some(p => p.endsWith('settings.json'));
   512â†’  const hasCoreSystem = paths.some(p => p.includes('PAI/SYSTEM/'));
   513â†’  const hasCoreUser = paths.some(p => p.includes('PAI/USER/'));
   514â†’
   515â†’  let title = '';
   516â†’
   517â†’  // Single skill update
   518â†’  if (skillNames.size === 1) {
   519â†’    const skill = [...skillNames][0];
   520â†’    if (hasSkillMd) {
   521â†’      title = `${skill} Skill Definition Update`;
   522â†’    } else if (hasWorkflows) {
   523â†’      const workflowNames = paths
   524â†’        .filter(p => p.includes('/Workflows/'))
   525â†’        .map(p => basename(p, '.md'));
   526â†’      if (workflowNames.length === 1) {
   527â†’        title = `${skill} ${workflowNames[0]} Workflow Update`;
   528â†’      } else {
   529â†’        title = `${skill} Workflows Updated`;
   530â†’      }
   531â†’    } else if (hasTools) {
   532â†’      const toolNames = paths
   533â†’        .filter(p => p.includes('/Tools/'))
   534â†’        .map(p => basename(p, '.ts'));
   535â†’      if (toolNames.length === 1) {
   536â†’        title = `${skill} ${toolNames[0]} Tool Update`;
   537â†’      } else {
   538â†’        title = `${skill} Tools Updated`;
   539â†’      }
   540â†’    } else {
   541â†’      title = `${skill} Skill Files Updated`;
   542â†’    }
   543â†’  }
   544â†’  // Multiple skills
   545â†’  else if (skillNames.size > 1 && skillNames.size <= 3) {
   546â†’    const skills = [...skillNames].slice(0, 3).join(' and ');
   547â†’    title = `${skills} Skills Updated`;
   548â†’  }
   549â†’  // Hook changes
   550â†’  else if (hasHooks) {
   551â†’    const hookNames = paths
   552â†’      .filter(p => p.includes('hooks/'))
   553â†’      .map(p => basename(p, '.ts').replace('.hook', ''));
   554â†’    if (hookNames.length === 1) {
   555â†’      title = `${hookNames[0]} Hook Updated`;
   556â†’    } else if (hookNames.length <= 3) {
   557â†’      title = `${hookNames.slice(0, 3).join(', ')} Hooks Updated`;
   558â†’    } else {
   559â†’      title = `Hook System Updates`;
   560â†’    }
   561â†’  }
   562â†’  // Config changes
   563â†’  else if (hasConfig) {
   564â†’    title = 'System Configuration Updated';
   565â†’  }
   566â†’  // Core system changes
   567â†’  else if (hasCoreSystem) {
   568â†’    const docNames = paths
   569â†’      .filter(p => p.includes('PAI/SYSTEM/'))
   570â†’      .map(p => basename(p, '.md'));
   571â†’    if (docNames.length === 1) {
   572â†’      title = `${docNames[0]} Documentation Updated`;
   573â†’    } else {
   574â†’      title = 'PAI System Documentation Updated';
   575â†’    }
   576â†’  }
   577â†’  // Core user changes
   578â†’  else if (hasCoreUser) {
   579â†’    const docNames = paths
   580â†’      .filter(p => p.includes('PAI/USER/'))
   581â†’      .map(p => basename(p, '.md'));
   582â†’    if (docNames.length === 1) {
   583â†’      title = `${docNames[0]} User Config Updated`;
   584â†’    } else {
   585â†’      title = 'User Configuration Updated';
   586â†’    }
   587â†’  }
   588â†’  // Fallback
   589â†’  else {
