   242â†’function applySoulUpdate(paiDir: string, update: SoulUpdate): boolean {
   243â†’  const soulPath = join(paiDir, 'skills/PAI/USER/KAI.md');
   244â†’
   245â†’  if (!existsSync(soulPath)) return false;
   246â†’
   247â†’  let content = readFileSync(soulPath, 'utf-8');
   248â†’
   249â†’  // Find the appropriate section and append
   250â†’  const sectionMarkers: Record<string, string> = {
   251â†’    'figuring_out': '### Things I\'m Still Figuring Out',
   252â†’    'learned': '### Things I\'ve Learned About Myself',
   253â†’  };
   254â†’
   255â†’  const marker = sectionMarkers[update.section];
   256â†’  if (!marker) return false;
   257â†’
   258â†’  const markerIndex = content.indexOf(marker);
   259â†’  if (markerIndex === -1) return false;
   260â†’
   261â†’  // Find the end of the section (next ## or end of file)
   262â†’  const sectionStart = markerIndex + marker.length;
   263â†’  const nextSection = content.indexOf('\n## ', sectionStart);
   264â†’  const sectionEnd = nextSection !== -1 ? nextSection : content.length;
   265â†’
   266â†’  // Insert the new item at the end of the section
   267â†’  const before = content.substring(0, sectionEnd);
   268â†’  const after = content.substring(sectionEnd);
   269â†’
   270â†’  // Add newline if needed
   271â†’  const newContent = before.trimEnd() + '\n' + update.proposed + '\n' + after;
   272â†’
   273â†’  writeFileSync(soulPath, newContent);
   274â†’  return true;
   275â†’}
