     2â†’/**
     3â†’ * Metadata Extraction Library for UOCS Enhancement
     4â†’ *
     5â†’ * Extracts agent instance IDs, parent-child relationships, and session info
     6â†’ * from Task tool calls and other tool inputs.
     7â†’ *
     8â†’ * Design Philosophy: Optional extraction with graceful fallbacks
     9â†’ * - If instance IDs are present in descriptions/prompts, extract them
    10â†’ * - If not present, fall back to agent type only
    11â†’ * - Never fail - always return usable metadata
    12â†’ */
    13â†’
    14â†’export interface AgentInstanceMetadata {
    15â†’  agent_instance_id?: string;      // "perplexity-researcher-1" (full ID)
    16â†’  agent_type?: string;              // "perplexity-researcher" (base type)
    17â†’  instance_number?: number;         // 1 (sequence number)
    18â†’  parent_session_id?: string;       // Session that spawned this agent
    19â†’  parent_task_id?: string;          // Task ID that spawned this agent
    20â†’}
    21â†’
    22â†’/**
    23â†’ * Extract agent instance ID from Task tool input
    24â†’ *
    25â†’ * Looks for patterns in priority order:
    26â†’ * 1. [agent-type-N] in description (e.g., "Research topic [perplexity-researcher-1]")
    27â†’ * 2. [AGENT_INSTANCE: agent-type-N] in prompt
    28â†’ * 3. subagent_type field (fallback to just type, no instance number)
    29â†’ *
    30â†’ * @param toolInput The tool input object from PreToolUse/PostToolUse hooks
    31â†’ * @param description Optional description field from tool input
    32â†’ * @returns Metadata object with extracted information
    33â†’ */
    34â†’export function extractAgentInstanceId(
    35â†’  toolInput: any,
    36â†’  description?: string
    37â†’): AgentInstanceMetadata {
    38â†’  const result: AgentInstanceMetadata = {};
    39â†’
    40â†’  // Strategy 1: Extract from description [agent-type-N]
    41â†’  // Example: "Research consumer complaints [perplexity-researcher-1]"
    42â†’  if (description) {
    43â†’    const descMatch = description.match(/\[([a-z-]+-researcher)-(\d+)\]/);
    44â†’    if (descMatch) {
    45â†’      result.agent_type = descMatch[1];
    46â†’      result.instance_number = parseInt(descMatch[2], 10);
    47â†’      result.agent_instance_id = `${result.agent_type}-${result.instance_number}`;
    48â†’    }
    49â†’  }
    50â†’
    51â†’  // Strategy 2: Extract from prompt [AGENT_INSTANCE: ...]
    52â†’  // Example: "[AGENT_INSTANCE: perplexity-researcher-1]"
    53â†’  if (!result.agent_instance_id && toolInput?.prompt && typeof toolInput.prompt === 'string') {
    54â†’    const promptMatch = toolInput.prompt.match(/\[AGENT_INSTANCE:\s*([^\]]+)\]/);
    55â†’    if (promptMatch) {
    56â†’      result.agent_instance_id = promptMatch[1].trim();
    57â†’
    58â†’      // Parse agent type and instance number from ID
    59â†’      const parts = result.agent_instance_id.match(/^([a-z-]+)-(\d+)$/);
    60â†’      if (parts) {
    61â†’        result.agent_type = parts[1];
    62â†’        result.instance_number = parseInt(parts[2], 10);
    63â†’      }
    64â†’    }
    65â†’  }
    66â†’
    67â†’  // Strategy 3: Extract parent session from prompt
    68â†’  // Example: "[PARENT_SESSION: b7062b5a-03d3-4168-9555-a748e0b2efa3]"
    69â†’  if (toolInput?.prompt && typeof toolInput.prompt === 'string') {
    70â†’    const parentSessionMatch = toolInput.prompt.match(/\[PARENT_SESSION:\s*([^\]]+)\]/);
    71â†’    if (parentSessionMatch) {
    72â†’      result.parent_session_id = parentSessionMatch[1].trim();
    73â†’    }
    74â†’
    75â†’    // Extract parent task from prompt
    76â†’    // Example: "[PARENT_TASK: research_1731445892345]"
    77â†’    const parentTaskMatch = toolInput.prompt.match(/\[PARENT_TASK:\s*([^\]]+)\]/);
    78â†’    if (parentTaskMatch) {
    79â†’      result.parent_task_id = parentTaskMatch[1].trim();
    80â†’    }
    81â†’  }
    82â†’
    83â†’  // Strategy 4: Fallback to subagent_type if available (no instance number)
    84â†’  // This ensures we at least capture the agent type even without instance IDs
    85â†’  if (!result.agent_type && toolInput?.subagent_type) {
    86â†’    result.agent_type = toolInput.subagent_type;
    87â†’  }
    88â†’
    89â†’  return result;
    90â†’}
    91â†’
    92â†’/**
    93â†’ * Enrich event with agent metadata
    94â†’ *
    95â†’ * Takes a base event object and adds agent instance metadata to it.
    96â†’ * Returns a new object with merged metadata.
    97â†’ *
    98â†’ * @param event Base event object (from PreToolUse/PostToolUse)
    99â†’ * @param toolInput Tool input object
   100â†’ * @param description Optional description field
   101â†’ * @returns Enriched event with agent metadata
   102â†’ */
   103â†’export function enrichEventWithAgentMetadata(
   104â†’  event: any,
   105â†’  toolInput: any,
   106â†’  description?: string
   107â†’): any {
   108â†’  const metadata = extractAgentInstanceId(toolInput, description);
   109â†’
   110â†’  // Only add fields that have values (keep events clean)
   111â†’  const enrichedEvent = { ...event };
   112â†’
   113â†’  if (metadata.agent_instance_id) {
   114â†’    enrichedEvent.agent_instance_id = metadata.agent_instance_id;
   115â†’  }
   116â†’
   117â†’  if (metadata.agent_type) {
   118â†’    enrichedEvent.agent_type = metadata.agent_type;
   119â†’  }
   120â†’
   121â†’  if (metadata.instance_number !== undefined) {
   122â†’    enrichedEvent.instance_number = metadata.instance_number;
   123â†’  }
   124â†’
   125â†’  if (metadata.parent_session_id) {
   126â†’    enrichedEvent.parent_session_id = metadata.parent_session_id;
   127â†’  }
   128â†’
   129â†’  if (metadata.parent_task_id) {
   130â†’    enrichedEvent.parent_task_id = metadata.parent_task_id;
   131â†’  }
   132â†’
   133â†’  return enrichedEvent;
   134â†’}
