   136â†’/**
   137â†’ * Check if a tool call is spawning a subagent
   138â†’ *
   139â†’ * @param toolName Name of the tool being called
   140â†’ * @param toolInput Tool input object
   141â†’ * @returns true if this is a Task tool call spawning an agent
   142â†’ */
   143â†’export function isAgentSpawningCall(toolName: string, toolInput: any): boolean {
   144â†’  return toolName === 'Task' && toolInput?.subagent_type !== undefined;
   145â†’}
